{
  "name": "@node/interactive-map",
  "version": "1.0.0",
  "description": "Interactive map module with markers, circles, categories, and location search using Leaflet.js and OpenStreetMap",
  "modnet": {
    "contentType": "geo",
    "structure": "collection",
    "mechanics": ["filter", "track"],
    "boundary": "ask",
    "scale": 2
  },
  "dependencies": {
    "leaflet": "^1.9.4"
  }
}

export type MarkerCategory = {
  id: string
  name: string
  color: string
}

export type MapMarker = {
  id: string
  lat: number
  lng: number
  title: string
  description: string
  categoryId: string
  createdAt: string
}

export type MapCircle = {
  id: string
  lat: number
  lng: number
  radius: number
  color: string
  label: string
  createdAt: string
}

export type MapState = {
  markers: MapMarker[]
  circles: MapCircle[]
  categories: MarkerCategory[]
  center: { lat: number; lng: number }
  zoom: number
}

export type SearchResult = {
  lat: number
  lng: number
  displayName: string
}

export type MarkerFormData = {
  title: string
  description: string
  categoryId: string
  lat: number
  lng: number
}

export type CircleFormData = {
  lat: number
  lng: number
  radius: number
  color: string
  label: string
}

import type { MapState, MapMarker, MapCircle, MarkerCategory } from './types'

const DATA_DIR = `${import.meta.dir}/data`
const STATE_FILE = `${DATA_DIR}/state.json`

const DEFAULT_CATEGORIES: MarkerCategory[] = [
  { id: 'default', name: 'General', color: '#2563eb' },
  { id: 'food', name: 'Food & Drink', color: '#dc2626' },
  { id: 'nature', name: 'Nature', color: '#16a34a' },
  { id: 'culture', name: 'Culture', color: '#9333ea' },
  { id: 'transport', name: 'Transport', color: '#ea580c' },
  { id: 'shopping', name: 'Shopping', color: '#d946ef' },
]

const DEFAULT_STATE: MapState = {
  markers: [],
  circles: [],
  categories: DEFAULT_CATEGORIES,
  center: { lat: 51.505, lng: -0.09 },
  zoom: 13,
}

export const loadState = async (): Promise<MapState> => {
  const file = Bun.file(STATE_FILE)
  if (await file.exists()) {
    const text = await file.text()
    return JSON.parse(text) as MapState
  }
  await saveState(DEFAULT_STATE)
  return DEFAULT_STATE
}

export const saveState = async (state: MapState): Promise<void> => {
  await Bun.write(STATE_FILE, JSON.stringify(state, null, 2))
}

export const addMarker = async (marker: MapMarker): Promise<MapState> => {
  const state = await loadState()
  state.markers.push(marker)
  await saveState(state)
  return state
}

export const removeMarker = async (markerId: string): Promise<MapState> => {
  const state = await loadState()
  state.markers = state.markers.filter((m) => m.id !== markerId)
  await saveState(state)
  return state
}

export const addCircle = async (circle: MapCircle): Promise<MapState> => {
  const state = await loadState()
  state.circles.push(circle)
  await saveState(state)
  return state
}

export const removeCircle = async (circleId: string): Promise<MapState> => {
  const state = await loadState()
  state.circles = state.circles.filter((c) => c.id !== circleId)
  await saveState(state)
  return state
}

export const addCategory = async (category: MarkerCategory): Promise<MapState> => {
  const state = await loadState()
  if (!state.categories.some((c) => c.id === category.id)) {
    state.categories.push(category)
    await saveState(state)
  }
  return state
}

export const updateCenter = async (lat: number, lng: number, zoom?: number): Promise<MapState> => {
  const state = await loadState()
  state.center = { lat, lng }
  if (zoom !== undefined) state.zoom = zoom
  await saveState(state)
  return state
}

import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '1',
  })

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    throw new Error(`Geocoding failed: ${response.statusText}`)
  }

  const data = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

import type { MapMarker, MapCircle, MarkerCategory, MarkerFormData, CircleFormData } from './types'

export const createMarkerId = (): string =>
  `marker_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const createCircleId = (): string =>
  `circle_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`

export const createMarker = (data: MarkerFormData): MapMarker => ({
  id: createMarkerId(),
  lat: data.lat,
  lng: data.lng,
  title: data.title,
  description: data.description,
  categoryId: data.categoryId,
  createdAt: new Date().toISOString(),
})

export const createCircle = (data: CircleFormData): MapCircle => ({
  id: createCircleId(),
  lat: data.lat,
  lng: data.lng,
  radius: data.radius,
  color: data.color,
  label: data.label,
  createdAt: new Date().toISOString(),
})

export const groupMarkersByCategory = (
  markers: MapMarker[],
  categories: MarkerCategory[]
): Map<MarkerCategory, MapMarker[]> => {
  const grouped = new Map<MarkerCategory, MapMarker[]>()
  for (const category of categories) {
    const catMarkers = markers.filter((m) => m.categoryId === category.id)
    if (catMarkers.length > 0) {
      grouped.set(category, catMarkers)
    }
  }
  const uncategorized = markers.filter(
    (m) => !categories.some((c) => c.id === m.categoryId)
  )
  if (uncategorized.length > 0) {
    const fallback: MarkerCategory = { id: '_uncategorized', name: 'Uncategorized', color: '#6b7280' }
    grouped.set(fallback, uncategorized)
  }
  return grouped
}

export const getCategoryColor = (categoryId: string, categories: MarkerCategory[]): string => {
  const cat = categories.find((c) => c.id === categoryId)
  return cat?.color ?? '#6b7280'
}

