const renderMarkerList = (state: MapState) => {
  const grouped = groupMarkersByCategory(state.markers, state.categories)
  if (state.markers.length === 0) {
    return h('div', { style: styles.emptyState },
      h('p', {}, 'No markers yet.'),
      h('p', {}, 'Click the map or use the form to add one.'),
    )
  }
  const groups: ReturnType<typeof h>[] = []
  grouped.forEach((markers, category) => {
    groups.push(
      h('div', { style: styles.markerGroup, key: category.id },
        h('p', { style: styles.markerGroupTitle },
          h('span', { style: styles.categoryDot(category.color) }),
          `${category.name} (${markers.length})`,
        ),
        ...markers.map((m) => renderMarkerItem(m, category.color)),
      )
    )
  })
  return h('div', { style: styles.markerList }, ...groups)
}

