        ),
      ),
      h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }),
      h('script', {},
        renderClientScript(state),
      ),
    ),
  )

  return createSSR(template)
}

const renderClientScript = (state: MapState): string => `
(function() {
  var state = ${JSON.stringify(state)};
  var hiddenCategories = {};
  var leafletMarkers = {};
  var leafletCircles = {};

  // Initialize map
  var map = L.map('map').setView([state.center.lat, state.center.lng], state.zoom);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(map);

  // Color-coded marker icons
  function createColorIcon(color) {
    return L.divIcon({
      className: 'custom-marker',
      html: '<div style="background:' + color + ';width:24px;height:24px;border-radius:50%;border:3px solid white;box-shadow:0 2px 6px rgba(0,0,0,0.3);"></div>',
      iconSize: [24, 24],
      iconAnchor: [12, 12],
      popupAnchor: [0, -14],
    });
  }

  function getCategoryColor(categoryId) {
    var cat = state.categories.find(function(c) { return c.id === categoryId; });
    return cat ? cat.color : '#6b7280';
  }

  function getCategoryName(categoryId) {
    var cat = state.categories.find(function(c) { return c.id === categoryId; });
    return cat ? cat.name : 'Uncategorized';
  }

  // Render markers on map
  function renderMarkers() {
    Object.values(leafletMarkers).forEach(function(m) { map.removeLayer(m); });
    leafletMarkers = {};
    state.markers.forEach(function(marker) {
      if (hiddenCategories[marker.categoryId]) return;
      var color = getCategoryColor(marker.categoryId);
      var lMarker = L.marker([marker.lat, marker.lng], { icon: createColorIcon(color) })
        .addTo(map)
        .bindPopup(
          '<div class="marker-popup-title">' + escapeHtml(marker.title) + '</div>' +
          (marker.description ? '<div class="marker-popup-desc">' + escapeHtml(marker.description) + '</div>' : '') +
          '<div class="marker-popup-category">' + escapeHtml(getCategoryName(marker.categoryId)) + '</div>'
        );
      leafletMarkers[marker.id] = lMarker;
    });
  }

  // Render circles on map
  function renderCircles() {
    Object.values(leafletCircles).forEach(function(c) { map.removeLayer(c); });
    leafletCircles = {};
    state.circles.forEach(function(circle) {
      var lCircle = L.circle([circle.lat, circle.lng], {
        radius: circle.radius,
        color: circle.color,
        fillColor: circle.color,
        fillOpacity: 0.15,
        weight: 2,
      }).addTo(map);
      if (circle.label) {
        lCircle.bindPopup('<strong>' + escapeHtml(circle.label) + '</strong>');
      }
      leafletCircles[circle.id] = lCircle;
    });
  }

  function escapeHtml(text) {
    var div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }

  renderMarkers();
  renderCircles();

  // Tab switching
  var tabs = ['markers', 'add-marker', 'add-circle'];
  function switchTab(name) {
    tabs.forEach(function(t) {
      var content = document.getElementById('tab-content-' + t);
      var btn = document.getElementById('tab-' + t);
      if (content) content.style.display = t === name ? 'block' : 'none';
      if (btn) {
        btn.style.backgroundColor = t === name ? '#ffffff' : '#f1f5f9';
        btn.style.color = t === name ? '#2563eb' : '#64748b';
        btn.style.borderBottom = t === name ? '2px solid #2563eb' : '2px solid transparent';
      }
    });
  }
  document.getElementById('tab-markers').onclick = function() { switchTab('markers'); };
  document.getElementById('tab-add-marker').onclick = function() { switchTab('add-marker'); };
  document.getElementById('tab-add-circle').onclick = function() { switchTab('add-circle'); };

  // Map click -> populate lat/lng fields
  map.on('click', function(e) {
    var latInputs = document.querySelectorAll('[p-target="marker-lat"], [p-target="circle-lat"]');
    var lngInputs = document.querySelectorAll('[p-target="marker-lng"], [p-target="circle-lng"]');
    latInputs.forEach(function(input) { input.value = e.latlng.lat.toFixed(6); });
    lngInputs.forEach(function(input) { input.value = e.latlng.lng.toFixed(6); });
  });

  // Category filter toggle
  document.querySelectorAll('[p-trigger^="category-toggle"]').forEach(function(el) {
    el.onclick = function() {
      var catId = el.getAttribute('data-category-id');
      hiddenCategories[catId] = !hiddenCategories[catId];
      var cat = state.categories.find(function(c) { return c.id === catId; });
      if (cat) {
        if (hiddenCategories[catId]) {
          el.style.backgroundColor = '#ffffff';
          el.style.color = cat.color;
        } else {
          el.style.backgroundColor = cat.color;
          el.style.color = '#ffffff';
        }
      }
      renderMarkers();
    };
  });

  // Marker click in sidebar -> center map
  document.querySelectorAll('[p-trigger^="marker-click"]').forEach(function(el) {
    el.onclick = function() {
      var lat = parseFloat(el.getAttribute('data-lat'));
      var lng = parseFloat(el.getAttribute('data-lng'));
      var markerId = el.getAttribute('data-marker-id');
      map.setView([lat, lng], 16);
      if (leafletMarkers[markerId]) {
        leafletMarkers[markerId].openPopup();
      }
    };
  });

  // Delete marker
  document.querySelectorAll('[p-trigger^="marker-delete"]').forEach(function(el) {
    el.onclick = function(e) {
      e.stopPropagation();
      var markerId = el.getAttribute('p-trigger').split(':')[1];
      fetch('/api/markers/' + markerId, { method: 'DELETE' })
        .then(function() { location.reload(); })
        .catch(function(err) { console.error('Delete failed:', err); });
    };
  });

  // Add marker form
  var markerSubmit = document.querySelector('[p-trigger="marker-submit"]');
  if (markerSubmit) {
    markerSubmit.onclick = function() {
      var title = document.querySelector('[p-target="marker-title"]').value.trim();
      var desc = document.querySelector('[p-target="marker-desc"]').value.trim();
      var categoryId = document.querySelector('[p-target="marker-category"]').value;
      var lat = parseFloat(document.querySelector('[p-target="marker-lat"]').value);
      var lng = parseFloat(document.querySelector('[p-target="marker-lng"]').value);
      if (!title || isNaN(lat) || isNaN(lng)) {
        alert('Please fill in title and coordinates (click the map to set them).');
        return;
      }
      fetch('/api/markers', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ title: title, description: desc, categoryId: categoryId, lat: lat, lng: lng }),
      }).then(function() { location.reload(); })
        .catch(function(err) { console.error('Add marker failed:', err); });
    };
  }

  // Add circle form
  var circleSubmit = document.querySelector('[p-trigger="circle-submit"]');
  if (circleSubmit) {
    circleSubmit.onclick = function() {
      var label = document.querySelector('[p-target="circle-label"]').value.trim();
      var lat = parseFloat(document.querySelector('[p-target="circle-lat"]').value);
      var lng = parseFloat(document.querySelector('[p-target="circle-lng"]').value);
      var radius = parseFloat(document.querySelector('[p-target="circle-radius"]').value);
      var color = document.querySelector('[p-target="circle-color"]').value;
      if (isNaN(lat) || isNaN(lng) || isNaN(radius)) {
        alert('Please fill in coordinates and radius.');
        return;
      }
      fetch('/api/circles', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ label: label, lat: lat, lng: lng, radius: radius, color: color }),
      }).then(function() { location.reload(); })
        .catch(function(err) { console.error('Add circle failed:', err); });
    };
  }

  // Location search
  var searchInput = document.getElementById('search-input');
  var searchBtn = document.getElementById('search-btn');
  var searchResults = document.getElementById('search-results');

  function doSearch() {
    var query = searchInput.value.trim();
    if (!query) return;
    fetch('/api/search?q=' + encodeURIComponent(query))
      .then(function(r) { return r.json(); })
      .then(function(results) {
        if (results.length === 0) {
          searchResults.innerHTML = '<div class="search-result-item" style="color:#94a3b8;">No results found</div>';
          searchResults.style.display = 'block';
          return;
        }
        searchResults.innerHTML = results.map(function(r) {
          return '<div class="search-result-item" data-lat="' + r.lat + '" data-lng="' + r.lng + '">' + escapeHtml(r.displayName) + '</div>';
        }).join('');
        searchResults.style.display = 'block';
        searchResults.querySelectorAll('.search-result-item').forEach(function(el) {
          el.onclick = function() {
            var lat = parseFloat(el.getAttribute('data-lat'));
            var lng = parseFloat(el.getAttribute('data-lng'));
            if (!isNaN(lat) && !isNaN(lng)) {
              map.flyTo([lat, lng], 15);
            }
            searchResults.style.display = 'none';
            searchInput.value = el.textContent;
          };
        });
      })
      .catch(function(err) { console.error('Search failed:', err); });
  }

  searchBtn.onclick = doSearch;
  searchInput.onkeydown = function(e) {
    if (e.key === 'Enter') doSearch();
  };

  document.addEventListener('click', function(e) {
    if (!searchResults.contains(e.target) && e.target !== searchInput) {
      searchResults.style.display = 'none';
    }
  });
})();
`

import { loadState, addMarker, removeMarker, addCircle, removeCircle } from './store'
import { createMarker, createCircle } from './markers'
import { searchLocation } from './search'
import { renderApp } from './render'
import type { MarkerFormData, CircleFormData } from './types'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url

    // Serve main page
    if (pathname === '/' && req.method === 'GET') {
      const state = await loadState()
      const html = renderApp(state)
      return htmlResponse(html)
    }

    // API: Search location
    if (pathname === '/api/search' && req.method === 'GET') {
      const query = url.searchParams.get('q')
      if (!query) {
        return jsonResponse({ error: 'Missing query parameter q' }, 400)
      }
      const results = await searchLocation(query)
      return jsonResponse(results)
    }

    // API: List markers
    if (pathname === '/api/markers' && req.method === 'GET') {
      const state = await loadState()
      return jsonResponse(state.markers)
    }

    // API: Add marker
    if (pathname === '/api/markers' && req.method === 'POST') {
      const body = (await req.json()) as MarkerFormData
      if (!body.title || body.lat == null || body.lng == null) {
        return jsonResponse({ error: 'title, lat, lng are required' }, 400)
      }
      const marker = createMarker({
        title: body.title,
        description: body.description ?? '',
        categoryId: body.categoryId ?? 'default',
        lat: body.lat,
        lng: body.lng,
      })
      const state = await addMarker(marker)
      return jsonResponse(state)
    }

    // API: Delete marker
    const markerDeleteMatch = pathname.match(/^\/api\/markers\/(.+)$/)
    if (markerDeleteMatch && req.method === 'DELETE') {
      const markerId = markerDeleteMatch[1]
      const state = await removeMarker(markerId)
      return jsonResponse(state)
    }

    // API: List circles
    if (pathname === '/api/circles' && req.method === 'GET') {
      const state = await loadState()
      return jsonResponse(state.circles)
    }

    // API: Add circle
    if (pathname === '/api/circles' && req.method === 'POST') {
      const body = (await req.json()) as CircleFormData
      if (body.lat == null || body.lng == null || body.radius == null) {
        return jsonResponse({ error: 'lat, lng, radius are required' }, 400)
      }
      const circle = createCircle({
        lat: body.lat,
        lng: body.lng,
        radius: body.radius,
        color: body.color ?? '#2563eb',
        label: body.label ?? '',
      })
      const state = await addCircle(circle)
      return jsonResponse(state)
    }

    // API: Delete circle
    const circleDeleteMatch = pathname.match(/^\/api\/circles\/(.+)$/)
    if (circleDeleteMatch && req.method === 'DELETE') {
      const circleId = circleDeleteMatch[1]
      const state = await removeCircle(circleId)
      return jsonResponse(state)
    }

    // API: Get state
    if (pathname === '/api/state' && req.method === 'GET') {
      const state = await loadState()
      return jsonResponse(state)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Interactive Map running at http://localhost:${server.port}`)

