import type { MapMarker, MapCircle } from './types'

const MARKERS_PATH = './data/markers.json'
const CIRCLES_PATH = './data/circles.json'

const generateId = (): string =>
  `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`

export const loadMarkers = async (): Promise<MapMarker[]> => {
  try {
    const file = Bun.file(MARKERS_PATH)
    const exists = await file.exists()
    if (!exists) return []
    const text = await file.text()
    return JSON.parse(text) as MapMarker[]
  } catch {
    return []
  }
}

export const saveMarkers = async (markers: MapMarker[]): Promise<void> => {
  await Bun.write(MARKERS_PATH, JSON.stringify(markers, null, 2))
}

export const addMarker = async (
  marker: Omit<MapMarker, 'id' | 'createdAt'>
): Promise<MapMarker> => {
  const markers = await loadMarkers()
  const newMarker: MapMarker = {
    ...marker,
    id: generateId(),
    createdAt: new Date().toISOString(),
  }
  markers.push(newMarker)
  await saveMarkers(markers)
  return newMarker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await loadMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await saveMarkers(filtered)
  return true
}

export const loadCircles = async (): Promise<MapCircle[]> => {
  try {
    const file = Bun.file(CIRCLES_PATH)
    const exists = await file.exists()
    if (!exists) return []
    const text = await file.text()
    return JSON.parse(text) as MapCircle[]
  } catch {
    return []
  }
}

export const saveCircles = async (circles: MapCircle[]): Promise<void> => {
  await Bun.write(CIRCLES_PATH, JSON.stringify(circles, null, 2))
}

export const addCircle = async (
  circle: Omit<MapCircle, 'id' | 'createdAt'>
): Promise<MapCircle> => {
  const circles = await loadCircles()
  const newCircle: MapCircle = {
    ...circle,
    id: generateId(),
    createdAt: new Date().toISOString(),
  }
  circles.push(newCircle)
  await saveCircles(circles)
  return newCircle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await loadCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await saveCircles(filtered)
  return true
}

import type { SearchResult } from './types'

const NOMINATIM_BASE = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (
  query: string
): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '1',
  })

  const response = await fetch(`${NOMINATIM_BASE}?${params}`, {
    headers: {
      'User-Agent': 'interactive-map-module/1.0',
    },
  })

  if (!response.ok) {
    throw new Error(`Nominatim search failed: ${response.status}`)
  }

  const data = (await response.json()) as Array<{
    lat: string
    lon: string
    display_name: string
  }>

  return data.map((item) => ({
    lat: parseFloat(item.lat),
    lng: parseFloat(item.lon),
    displayName: item.display_name,
  }))
}

