const renderSidebarMarkers = (markers: MapMarker[]): ReturnType<typeof h>[] => {
  const grouped: Partial<Record<MarkerCategory, MapMarker[]>> = {}
  for (const marker of markers) {
    const cat = marker.category
    if (!grouped[cat]) grouped[cat] = []
    grouped[cat]!.push(marker)
  }

  const elements: ReturnType<typeof h>[] = []
  for (const category of ALL_CATEGORIES) {
    const group = grouped[category]
    if (!group || group.length === 0) continue
    const color = CATEGORY_COLORS[category].hex
    const label = CATEGORY_LABELS[category]

    elements.push(
      h('div', { style: styles.categoryGroup },
        h('div', { style: styles.categoryHeader(color) }, `${label} (${group.length})`),
        ...group.map((marker) =>
          h('div', {
            style: styles.markerItem,
            'p-trigger': 'click:centerOnMarker',
            'data-marker-id': marker.id,
            'data-lat': String(marker.lat),
            'data-lng': String(marker.lng),
          },
            h('p', { style: styles.markerTitle },
              h('span', { style: styles.colorDot(color) }),
              ` ${marker.title}`
            ),
            marker.description
              ? h('p', { style: styles.markerDesc }, marker.description)
              : null,
            h('p', { style: styles.markerCoords },
              `${marker.lat.toFixed(5)}, ${marker.lng.toFixed(5)}`
            )
          )
        )
      )
    )
  }

  return elements
}

