/**
 * Client-side map controller.
 * Initializes Leaflet, binds UI events, and manages map interactions.
 */

import type { MapMarker, MapCircle, MarkerCategory } from './types'
import { CATEGORY_COLORS, ALL_CATEGORIES, buildMarkerSvg } from './categories'

declare const L: typeof import('leaflet')

type LeafletMarkerEntry = {
  data: MapMarker
  leafletMarker: L.Marker
}

type LeafletCircleEntry = {
  data: MapCircle
  leafletCircle: L.Circle
}

type MapController = {
  map: L.Map
  markers: LeafletMarkerEntry[]
  circles: LeafletCircleEntry[]
  activeCategories: Set<MarkerCategory>
  activeForm: 'marker' | 'circle'
}

const state: MapController = {
  map: null as unknown as L.Map,
  markers: [],
  circles: [],
  activeCategories: new Set(ALL_CATEGORIES),
  activeForm: 'marker',
}

const getTarget = (name: string): HTMLElement | null =>
  document.querySelector(`[p-target="${name}"]`)

const getInputValue = (name: string): string =>
  (getTarget(name) as HTMLInputElement | null)?.value ?? ''

const setInputValue = (name: string, value: string): void => {
  const el = getTarget(name) as HTMLInputElement | null
  if (el) el.value = value
}

const createLeafletIcon = (category: MarkerCategory): L.Icon =>
  L.icon({
    iconUrl: buildMarkerSvg(category),
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
  })

const addMarkerToMap = (marker: MapMarker): void => {
  const icon = createLeafletIcon(marker.category)
  const leafletMarker = L.marker([marker.lat, marker.lng], { icon })
    .addTo(state.map)
    .bindPopup(
      `<strong>${escapeHtml(marker.title)}</strong>` +
      (marker.description ? `<br/>${escapeHtml(marker.description)}` : '') +
      `<br/><small style="color:#6c757d">${CATEGORY_COLORS[marker.category].name} · ${marker.lat.toFixed(5)}, ${marker.lng.toFixed(5)}</small>`
    )

  if (!state.activeCategories.has(marker.category)) {
    state.map.removeLayer(leafletMarker)
  }

  state.markers.push({ data: marker, leafletMarker })
}

const addCircleToMap = (circle: MapCircle): void => {
  const leafletCircle = L.circle([circle.lat, circle.lng], {
    radius: circle.radius,
    color: circle.color,
    fillColor: circle.color,
    fillOpacity: 0.15,
    weight: 2,
  }).addTo(state.map)

  if (circle.label) {
    leafletCircle.bindPopup(`<strong>${escapeHtml(circle.label)}</strong><br/><small>Radius: ${circle.radius}m</small>`)
  }

  state.circles.push({ data: circle, leafletCircle })
}

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const postJson = async (url: string, body: Record<string, unknown>): Promise<unknown> => {
  const res = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  })
  return res.json()
}

const handleMapClick = (e: L.LeafletMouseEvent): void => {
  const { lat, lng } = e.latlng
  if (state.activeForm === 'marker') {
    setInputValue('markerLat', lat.toFixed(6))
    setInputValue('markerLng', lng.toFixed(6))
  } else {
    setInputValue('circleLat', lat.toFixed(6))
    setInputValue('circleLng', lng.toFixed(6))
  }
}

const handleSearch = async (): Promise<void> => {
  const query = getInputValue('searchInput').trim()
  if (!query) return

  try {
    const res = await fetch(`/api/search?q=${encodeURIComponent(query)}`)
    const results = (await res.json()) as Array<{ lat: number; lng: number; displayName: string }>
    if (results.length > 0) {
      const { lat, lng } = results[0]
      state.map.flyTo([lat, lng], 14, { duration: 1.5 })
    }
  } catch (err) {
    console.error('Search failed:', err)
  }
}

const handleAddMarker = async (): Promise<void> => {
  const title = getInputValue('markerTitle').trim()
  const description = getInputValue('markerDescription').trim()
  const category = getInputValue('markerCategory') as MarkerCategory
  const lat = parseFloat(getInputValue('markerLat'))
  const lng = parseFloat(getInputValue('markerLng'))

  if (!title || isNaN(lat) || isNaN(lng)) return

  const marker = (await postJson('/api/markers', {
    title,
    description,
    category,
    lat,
    lng,
  })) as MapMarker

  addMarkerToMap(marker)
  refreshSidebar()

  setInputValue('markerTitle', '')
  setInputValue('markerDescription', '')
  setInputValue('markerLat', '')
  setInputValue('markerLng', '')
}

const handleAddCircle = async (): Promise<void> => {
  const label = getInputValue('circleLabel').trim()
  const lat = parseFloat(getInputValue('circleLat'))
  const lng = parseFloat(getInputValue('circleLng'))
  const radius = parseFloat(getInputValue('circleRadius'))
  const color = getInputValue('circleColor') || '#2196F3'

  if (isNaN(lat) || isNaN(lng) || isNaN(radius) || radius <= 0) return

  const circle = (await postJson('/api/circles', {
    label,
    lat,
    lng,
    radius,
    color,
  })) as MapCircle

  addCircleToMap(circle)

  setInputValue('circleLabel', '')
  setInputValue('circleLat', '')
  setInputValue('circleLng', '')
  setInputValue('circleRadius', '')
}

const toggleCategory = (category: MarkerCategory, active: boolean): void => {
  if (active) {
    state.activeCategories.add(category)
  } else {
    state.activeCategories.delete(category)
  }

  for (const entry of state.markers) {
    if (entry.data.category === category) {
      if (active) {
        entry.leafletMarker.addTo(state.map)
      } else {
        state.map.removeLayer(entry.leafletMarker)
      }
    }
  }
}

const refreshSidebar = (): void => {
  const list = getTarget('markerList')
  if (!list) return

  const grouped: Partial<Record<MarkerCategory, LeafletMarkerEntry[]>> = {}
  for (const entry of state.markers) {
    const cat = entry.data.category
    if (!grouped[cat]) grouped[cat] = []
    grouped[cat]!.push(entry)
  }

  let html = ''
  for (const category of ALL_CATEGORIES) {
    const group = grouped[category]
    if (!group || group.length === 0) continue
    const color = CATEGORY_COLORS[category].hex
    const label = category.charAt(0).toUpperCase() + category.slice(1)

    html += `<div style="margin-bottom:12px">`
    html += `<div style="font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px;color:${color};padding:4px 8px;margin-bottom:4px">${label} (${group.length})</div>`

    for (const entry of group) {
      const m = entry.data
      html += `<div class="sidebar-marker" data-marker-id="${m.id}" data-lat="${m.lat}" data-lng="${m.lng}" style="padding:10px 12px;background:#fff;border-radius:8px;margin-bottom:4px;cursor:pointer;border:1px solid #e9ecef">`
      html += `<p style="font-size:14px;font-weight:500;color:#212529;margin:0 0 2px 0"><span style="width:12px;height:12px;border-radius:50%;background:${color};display:inline-block"></span> ${escapeHtml(m.title)}</p>`
      if (m.description) {
        html += `<p style="font-size:12px;color:#6c757d;margin:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${escapeHtml(m.description)}</p>`
      }
      html += `<p style="font-size:11px;color:#adb5bd;margin:4px 0 0 0">${m.lat.toFixed(5)}, ${m.lng.toFixed(5)}</p>`
      html += `</div>`
    }
    html += `</div>`
  }

  list.innerHTML = html

  list.querySelectorAll('.sidebar-marker').forEach((el) => {
    el.addEventListener('click', () => {
      const lat = parseFloat(el.getAttribute('data-lat') ?? '0')
      const lng = parseFloat(el.getAttribute('data-lng') ?? '0')
      const id = el.getAttribute('data-marker-id')
      state.map.flyTo([lat, lng], 16, { duration: 1 })

      const entry = state.markers.find((m) => m.data.id === id)
      if (entry) entry.leafletMarker.openPopup()
    })
  })
}

const switchForm = (form: 'marker' | 'circle'): void => {
  state.activeForm = form
  const markerForm = getTarget('markerForm')
  const circleForm = getTarget('circleForm')
  const markerTab = getTarget('markerTab') as HTMLButtonElement | null
  const circleTab = getTarget('circleTab') as HTMLButtonElement | null

  if (markerForm) markerForm.style.display = form === 'marker' ? 'block' : 'none'
  if (circleForm) circleForm.style.display = form === 'circle' ? 'block' : 'none'
  if (markerTab) {
    markerTab.style.backgroundColor = form === 'marker' ? '#2196F3' : '#e9ecef'
    markerTab.style.color = form === 'marker' ? 'white' : '#495057'
  }
  if (circleTab) {
    circleTab.style.backgroundColor = form === 'circle' ? '#2196F3' : '#e9ecef'
    circleTab.style.color = form === 'circle' ? 'white' : '#495057'
  }
}

export const initMap = (
  initialMarkers: MapMarker[],
  initialCircles: MapCircle[],
  center: [number, number] = [51.505, -0.09],
  zoom = 13
): void => {
  state.map = L.map('map').setView(center, zoom)

  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(state.map)

  for (const marker of initialMarkers) addMarkerToMap(marker)
  for (const circle of initialCircles) addCircleToMap(circle)

  state.map.on('click', handleMapClick)

  // Bind UI events
  const searchBtn = document.querySelector('[p-trigger="click:handleSearch"]')
  searchBtn?.addEventListener('click', handleSearch)

  const searchInput = getTarget('searchInput')
  searchInput?.addEventListener('keydown', (e) => {
    if ((e as KeyboardEvent).key === 'Enter') handleSearch()
  })

  const addMarkerBtn = document.querySelector('[p-trigger="click:addMarker"]')
  addMarkerBtn?.addEventListener('click', handleAddMarker)

  const addCircleBtn = document.querySelector('[p-trigger="click:addCircle"]')
  addCircleBtn?.addEventListener('click', handleAddCircle)

  const markerTabBtn = getTarget('markerTab')
  markerTabBtn?.addEventListener('click', () => switchForm('marker'))

  const circleTabBtn = getTarget('circleTab')
  circleTabBtn?.addEventListener('click', () => switchForm('circle'))

  // Category filter checkboxes
  document.querySelectorAll('[p-trigger="change:toggleCategory"]').forEach((el) => {
    el.addEventListener('change', (e) => {
      const input = e.target as HTMLInputElement
      const category = input.getAttribute('data-category') as MarkerCategory
      toggleCategory(category, input.checked)
    })
  })

  refreshSidebar()
}

/**
 * Server entry point.
 * Serves the map HTML page and API endpoints for markers, circles, and search.
 */

import { renderApp } from './render'
import { loadMarkers, addMarker, removeMarker, loadCircles, addCircle, removeCircle } from './store'
import { searchLocation } from './search'
import type { MarkerCategory } from './types'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const htmlPage = async (): Promise<string> => {
  const markers = await loadMarkers()
  const circles = await loadCircles()
  const appHtml = renderApp(markers, circles)

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Interactive Map</title>
  <link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"
    integrity="sha256-p4NxAoJBhIIN+hmNHrzRCf9tD/miZyoHS5obTRR9BMY="
    crossorigin=""/>
  <script src="https://unpkg.com/leaflet@1.9.4/dist/leaflet.js"
    integrity="sha256-20nQCchB9co0qIjJZRGuk2/Z9VM+kNiyxNV1lvTlZBo="
    crossorigin=""></script>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body { height: 100%; overflow: hidden; }
    .sidebar-marker:hover { box-shadow: 0 2px 8px rgba(0,0,0,0.1); }
  </style>
</head>
<body>
  ${appHtml}
  <script type="module">
    import { initMap } from '/client.js'
    const markers = ${JSON.stringify(markers)}
    const circles = ${JSON.stringify(circles)}
    initMap(markers, circles)
  </script>
</body>
</html>`
}

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const { pathname } = url

  // Serve client JS
  if (pathname === '/client.js') {
    const file = Bun.file('./client.ts')
    const transpiler = new Bun.Transpiler({ loader: 'ts' })
    const code = await transpiler.transform(await file.text())
    return new Response(code, {
      headers: { 'Content-Type': 'application/javascript' },
    })
  }

  // API: Search location
  if (pathname === '/api/search' && req.method === 'GET') {
    const query = url.searchParams.get('q') ?? ''
    if (!query) return jsonResponse([])
    try {
      const results = await searchLocation(query)
      return jsonResponse(results)
    } catch (err) {
      return jsonResponse({ error: 'Search failed' }, 500)
    }
  }

  // API: List markers
  if (pathname === '/api/markers' && req.method === 'GET') {
    const markers = await loadMarkers()
    return jsonResponse(markers)
  }

  // API: Add marker
  if (pathname === '/api/markers' && req.method === 'POST') {
    const body = (await req.json()) as {
      title: string
      description: string
      category: MarkerCategory
      lat: number
      lng: number
    }
    const marker = await addMarker({
      title: body.title,
      description: body.description,
      category: body.category ?? 'default',
      lat: body.lat,
      lng: body.lng,
    })
    return jsonResponse(marker, 201)
  }

  // API: Delete marker
  if (pathname.startsWith('/api/markers/') && req.method === 'DELETE') {
    const id = pathname.split('/').pop() ?? ''
    const removed = await removeMarker(id)
    return removed
      ? jsonResponse({ ok: true })
      : jsonResponse({ error: 'Not found' }, 404)
  }

  // API: List circles
  if (pathname === '/api/circles' && req.method === 'GET') {
    const circles = await loadCircles()
    return jsonResponse(circles)
  }

  // API: Add circle
  if (pathname === '/api/circles' && req.method === 'POST') {
    const body = (await req.json()) as {
      label: string
      lat: number
      lng: number
      radius: number
      color: string
    }
    const circle = await addCircle({
      label: body.label,
      lat: body.lat,
      lng: body.lng,
      radius: body.radius,
      color: body.color ?? '#2196F3',
    })
    return jsonResponse(circle, 201)
  }

  // API: Delete circle
  if (pathname.startsWith('/api/circles/') && req.method === 'DELETE') {
    const id = pathname.split('/').pop() ?? ''
    const removed = await removeCircle(id)
    return removed
      ? jsonResponse({ ok: true })
      : jsonResponse({ error: 'Not found' }, 404)
  }

  // Serve main page
  if (pathname === '/' || pathname === '/index.html') {
    const html = await htmlPage()
    return new Response(html, {
      headers: { 'Content-Type': 'text/html' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

Bun.serve({
  port: PORT,
  fetch: handleRequest,
})

console.log(`Interactive Map running at http://localhost:${PORT}`)

