export type MarkerCategory = {
  id: string
  name: string
  color: string
}

export type MapMarker = {
  id: string
  lat: number
  lng: number
  title: string
  description: string
  categoryId: string
  createdAt: string
}

export type MapCircle = {
  id: string
  lat: number
  lng: number
  radius: number
  color: string
  label: string
  createdAt: string
}

export type MapState = {
  center: { lat: number; lng: number }
  zoom: number
}

export type MapData = {
  markers: MapMarker[]
  circles: MapCircle[]
  categories: MarkerCategory[]
  state: MapState
}

export type SearchResult = {
  lat: number
  lng: number
  displayName: string
}

import type { MapMarker, MapCircle, MarkerCategory, MapState } from './types'

const DATA_DIR = `${import.meta.dir}/data`

const readJson = async <T>(filename: string): Promise<T> => {
  const file = Bun.file(`${DATA_DIR}/${filename}`)
  return file.json() as Promise<T>
}

const writeJson = async <T>(filename: string, data: T): Promise<void> => {
  await Bun.write(`${DATA_DIR}/${filename}`, JSON.stringify(data, null, 2))
}

export const getMarkers = (): Promise<MapMarker[]> => readJson('markers.json')

export const getCircles = (): Promise<MapCircle[]> => readJson('circles.json')

export const getCategories = (): Promise<MarkerCategory[]> => readJson('categories.json')

export const getState = (): Promise<MapState> => readJson('state.json')

export const saveMarkers = (markers: MapMarker[]): Promise<void> =>
  writeJson('markers.json', markers)

export const saveCircles = (circles: MapCircle[]): Promise<void> =>
  writeJson('circles.json', circles)

export const saveCategories = (categories: MarkerCategory[]): Promise<void> =>
  writeJson('categories.json', categories)

export const saveState = (state: MapState): Promise<void> =>
  writeJson('state.json', state)

export const addMarker = async (marker: Omit<MapMarker, 'id' | 'createdAt'>): Promise<MapMarker> => {
  const markers = await getMarkers()
  const newMarker: MapMarker = {
    ...marker,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  }
  markers.push(newMarker)
  await saveMarkers(markers)
  return newMarker
}

export const removeMarker = async (id: string): Promise<boolean> => {
  const markers = await getMarkers()
  const filtered = markers.filter((m) => m.id !== id)
  if (filtered.length === markers.length) return false
  await saveMarkers(filtered)
  return true
}

export const updateMarker = async (id: string, updates: Partial<Omit<MapMarker, 'id' | 'createdAt'>>): Promise<MapMarker | null> => {
  const markers = await getMarkers()
  const idx = markers.findIndex((m) => m.id === id)
  if (idx === -1) return null
  markers[idx] = { ...markers[idx], ...updates }
  await saveMarkers(markers)
  return markers[idx]
}

export const addCircle = async (circle: Omit<MapCircle, 'id' | 'createdAt'>): Promise<MapCircle> => {
  const circles = await getCircles()
  const newCircle: MapCircle = {
    ...circle,
    id: crypto.randomUUID(),
    createdAt: new Date().toISOString(),
  }
  circles.push(newCircle)
  await saveCircles(circles)
  return newCircle
}

export const removeCircle = async (id: string): Promise<boolean> => {
  const circles = await getCircles()
  const filtered = circles.filter((c) => c.id !== id)
  if (filtered.length === circles.length) return false
  await saveCircles(filtered)
  return true
}

export const addCategory = async (category: Omit<MarkerCategory, 'id'>): Promise<MarkerCategory> => {
  const categories = await getCategories()
  const newCategory: MarkerCategory = {
    ...category,
    id: crypto.randomUUID(),
  }
  categories.push(newCategory)
  await saveCategories(categories)
  return newCategory
}

export const removeCategory = async (id: string): Promise<boolean> => {
  if (id === 'default') return false
  const categories = await getCategories()
  const filtered = categories.filter((c) => c.id !== id)
  if (filtered.length === categories.length) return false
  await saveCategories(filtered)
  // Reassign orphaned markers to default
  const markers = await getMarkers()
  const updated = markers.map((m) =>
    m.categoryId === id ? { ...m, categoryId: 'default' } : m
  )
  await saveMarkers(updated)
  return true
}

import type { SearchResult } from './types'

const NOMINATIM_URL = 'https://nominatim.openstreetmap.org/search'

export const searchLocation = async (query: string): Promise<SearchResult[]> => {
  const params = new URLSearchParams({
    q: query,
    format: 'json',
    limit: '5',
    addressdetails: '1',
  })

  const response = await fetch(`${NOMINATIM_URL}?${params}`, {
    headers: {
      'User-Agent': 'InteractiveMapModule/1.0',
    },
  })

  if (!response.ok) {
    throw new Error(`Nominatim search failed: ${response.statusText}`)
  }

  type NominatimResult = {
    lat: string
    lon: string
    display_name: string
  }

  const results: NominatimResult[] = await response.json()

  return results.map((r) => ({
    lat: parseFloat(r.lat),
    lng: parseFloat(r.lon),
    displayName: r.display_name,
  }))
}

