type RenderOptions = {
  markers: MapMarker[]
  circles: MapCircle[]
  categories: MarkerCategory[]
  state: MapState
  activeCategories?: string[]
}

export const renderMap = (options: RenderOptions): string => {
  const { markers, circles, categories, state, activeCategories } = options
  const activeCats = activeCategories ?? categories.map((c) => c.id)
  const categoryMap = new Map(categories.map((c) => [c.id, c]))
  const filteredMarkers = markers.filter((m) => activeCats.includes(m.categoryId))

  const template = h(
    'html',
    { lang: 'en' },
    h(
      'head',
      {},
      h('meta', { charset: 'UTF-8' }),
      h('meta', { name: 'viewport', content: 'width=device-width, initial-scale=1.0' }),
      h('title', {}, 'Interactive Map'),
      h('link', {
        rel: 'stylesheet',
        href: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css',
      }),
      h('script', { src: 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js' }, ''),
      h(
        'style',
        {},
        `* { margin: 0; padding: 0; box-sizing: border-box; }
        .marker-item:hover { background-color: #f5f5f5 !important; }
        .action-btn:hover { background-color: #e8e8e8 !important; }
        .search-btn:hover { background-color: #2277ee !important; }
        .color-marker-icon {
          width: 25px; height: 41px; position: relative;
        }
        #map { width: 100%; height: 100%; }
        .modal-overlay {
          position: fixed; top: 0; left: 0; right: 0; bottom: 0;
          background: rgba(0,0,0,0.4); z-index: 2000;
          display: flex; align-items: center; justify-content: center;
        }
        .modal {
          background: #fff; border-radius: 12px; padding: 24px;
          min-width: 360px; max-width: 480px; box-shadow: 0 8px 32px rgba(0,0,0,0.2);
        }
        .modal h3 { margin-bottom: 16px; }
        .modal label { display: block; margin-bottom: 4px; font-size: 13px; font-weight: 500; color: #333; }
        .modal input, .modal select, .modal textarea {
          width: 100%; padding: 8px 12px; border: 1px solid #d0d0d0;
          border-radius: 6px; font-size: 14px; margin-bottom: 12px;
        }
        .modal textarea { resize: vertical; min-height: 60px; }
        .modal-actions { display: flex; gap: 8px; justify-content: flex-end; margin-top: 8px; }
        .modal-actions button {
          padding: 8px 18px; border-radius: 6px; font-size: 14px;
          cursor: pointer; border: 1px solid #d0d0d0;
        }
        .btn-primary { background: #3388ff; color: #fff; border-color: #3388ff !important; }
        .btn-primary:hover { background: #2277ee; }
        .btn-danger { background: #e74c3c; color: #fff; border-color: #e74c3c !important; }
        .leaflet-popup-content { min-width: 180px; }
        .popup-category { font-size: 11px; color: #888; margin-top: 4px; }
        .popup-desc { font-size: 13px; margin-top: 6px; color: #444; }
        .search-results {
          position: absolute; top: 100%; left: 0; right: 0;
          background: #fff; border: 1px solid #d0d0d0; border-radius: 0 0 6px 6px;
          max-height: 200px; overflow-y: auto; z-index: 10;
        }
        .search-result-item {
          padding: 8px 12px; cursor: pointer; font-size: 13px;
          border-bottom: 1px solid #f0f0f0;
        }
        .search-result-item:hover { background: #f5f5f5; }
        .empty-state { padding: 24px 16px; text-align: center; color: #999; font-size: 14px; }`
      )
    ),
    h(
      'body',
      {},
      h(
        'div',
        { id: 'app', style: 'display:flex;height:100vh;width:100vw;font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Roboto,sans-serif' },
        // Sidebar
        h(
          'div',
          {
            id: 'sidebar',
            style: 'width:320px;height:100vh;overflow-y:auto;background:#fff;border-right:1px solid #e0e0e0;display:flex;flex-direction:column;z-index:1000',
          },
          // Header with search
          h(
            'div',
            { style: 'padding:16px;border-bottom:1px solid #e0e0e0;background:#f8f9fa' },
            h('h2', { style: 'margin:0 0 12px 0;font-size:18px;font-weight:600;color:#1a1a2e' }, 'Interactive Map'),
            h(
              'div',
              { style: 'display:flex;gap:6px;position:relative', id: 'search-wrapper' },
              h('input', {
                type: 'text',
                id: 'search-input',
                placeholder: 'Search location...',
                style: 'flex:1;padding:8px 12px;border:1px solid #d0d0d0;border-radius:6px;font-size:14px;outline:none',
              }),
              h(
                'button',
                {
                  id: 'search-btn',
                  class: 'search-btn',
                  style: 'padding:8px 14px;background:#3388ff;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:14px;font-weight:500',
                },
                'Search'
              ),
              h('div', { id: 'search-results', class: 'search-results', style: 'display:none' })
            )
          ),
          // Category filter chips
          h(
            'div',
            { id: 'filter-bar', style: 'padding:12px 16px;border-bottom:1px solid #e0e0e0;display:flex;flex-wrap:wrap;gap:6px' },
            ...categories.map((cat) => renderCategoryChip(cat, activeCats.includes(cat.id)))
          ),
          // Marker list
          h(
            'div',
            { id: 'marker-list', style: 'flex:1;overflow-y:auto;padding:8px 0' },
            filteredMarkers.length > 0
              ? h(Fragment, {}, ...filteredMarkers.map((m) => renderMarkerItem(m, categoryMap.get(m.categoryId))))
              : h('div', { class: 'empty-state' }, 'No markers yet. Click "Add Marker" to get started.')
          ),
          // Actions
          h(
            'div',
            { style: 'padding:12px 16px;border-top:1px solid #e0e0e0;display:flex;gap:8px;background:#f8f9fa' },
            h('button', { id: 'btn-add-marker', class: 'action-btn', style: 'flex:1;padding:8px;border:1px solid #d0d0d0;border-radius:6px;background:#fff;cursor:pointer;font-size:13px;font-weight:500;text-align:center' }, 'Add Marker'),
            h('button', { id: 'btn-add-circle', class: 'action-btn', style: 'flex:1;padding:8px;border:1px solid #d0d0d0;border-radius:6px;background:#fff;cursor:pointer;font-size:13px;font-weight:500;text-align:center' }, 'Add Circle'),
            h('button', { id: 'btn-manage-cats', class: 'action-btn', style: 'flex:1;padding:8px;border:1px solid #d0d0d0;border-radius:6px;background:#fff;cursor:pointer;font-size:13px;font-weight:500;text-align:center' }, 'Categories')
          )
        ),
        // Map
        h('div', { id: 'map-container', style: 'flex:1;height:100vh;position:relative' }, h('div', { id: 'map' }))
      ),
      // Modal container
      h('div', { id: 'modal-root' }),
      // Client-side script
      h(
        'script',
        {},
        `
(function() {
  // State
  const mapState = ${JSON.stringify(state)};
  const markersData = ${JSON.stringify(markers)};
  const circlesData = ${JSON.stringify(circles)};
  const categoriesData = ${JSON.stringify(categories)};
  let activeCategories = ${JSON.stringify(activeCats)};
  let leafletMarkers = {};
  let leafletCircles = {};
  let addMode = null; // 'marker' | 'circle' | null

  // Init map
  const map = L.map('map').setView([mapState.center.lat, mapState.center.lng], mapState.zoom);
  L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
    maxZoom: 19,
  }).addTo(map);

  // Custom colored marker icon
  const createColorIcon = (color) => {
    const svg = \`<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 25 41" width="25" height="41">
      <path d="M12.5 0C5.6 0 0 5.6 0 12.5c0 2.4.7 4.7 1.9 6.6L12.5 41l10.6-21.9c1.2-1.9 1.9-4.2 1.9-6.6C25 5.6 19.4 0 12.5 0z" fill="\${color}" stroke="#fff" stroke-width="1"/>
      <circle cx="12.5" cy="12.5" r="5" fill="#fff"/>
    </svg>\`;
    return L.divIcon({
      html: svg,
      iconSize: [25, 41],
      iconAnchor: [12, 41],
      popupAnchor: [0, -35],
      className: '',
    });
  };

  const getCategoryById = (id) => categoriesData.find(c => c.id === id) || categoriesData[0];

  // Add markers to map
  const addMarkerToMap = (m) => {
    const cat = getCategoryById(m.categoryId);
    const icon = createColorIcon(cat.color);
    const marker = L.marker([m.lat, m.lng], { icon }).addTo(map);
    const popupHtml = \`<div>
      <strong>\${m.title}</strong>
      <div class="popup-category">\${cat.name}</div>
      \${m.description ? '<div class="popup-desc">' + m.description + '</div>' : ''}
      <div style="margin-top:8px;display:flex;gap:6px">
        <button onclick="window.__deleteMarker('\${m.id}')" style="padding:4px 10px;font-size:12px;border:1px solid #e74c3c;color:#e74c3c;background:#fff;border-radius:4px;cursor:pointer">Delete</button>
      </div>
    </div>\`;
    marker.bindPopup(popupHtml);
    leafletMarkers[m.id] = marker;
  };

  const addCircleToMap = (c) => {
    const circle = L.circle([c.lat, c.lng], {
      radius: c.radius,
      color: c.color,
      fillColor: c.color,
      fillOpacity: 0.15,
      weight: 2,
    }).addTo(map);
    if (c.label) {
      circle.bindPopup(\`<div>
        <strong>\${c.label}</strong>
        <div style="font-size:12px;color:#666">Radius: \${c.radius}m</div>
        <div style="margin-top:8px">
          <button onclick="window.__deleteCircle('\${c.id}')" style="padding:4px 10px;font-size:12px;border:1px solid #e74c3c;color:#e74c3c;background:#fff;border-radius:4px;cursor:pointer">Delete</button>
        </div>
      </div>\`);
    }
    leafletCircles[c.id] = circle;
  };

  // Render all
  const renderMarkers = () => {
    Object.values(leafletMarkers).forEach(m => map.removeLayer(m));
    leafletMarkers = {};
    markersData
      .filter(m => activeCategories.includes(m.categoryId))
      .forEach(addMarkerToMap);
  };

  const renderCircles = () => {
    Object.values(leafletCircles).forEach(c => map.removeLayer(c));
    leafletCircles = {};
    circlesData.forEach(addCircleToMap);
  };

  renderMarkers();
  renderCircles();

  // Update sidebar marker list
  const refreshSidebar = () => {
    const list = document.getElementById('marker-list');
    const filtered = markersData.filter(m => activeCategories.includes(m.categoryId));
    if (filtered.length === 0) {
      list.innerHTML = '<div class="empty-state">No markers yet. Click "Add Marker" to get started.</div>';
      return;
    }
    list.innerHTML = filtered.map(m => {
      const cat = getCategoryById(m.categoryId);
      return \`<div class="marker-item" data-marker-id="\${m.id}" data-lat="\${m.lat}" data-lng="\${m.lng}" style="padding:10px 16px;cursor:pointer;border-bottom:1px solid #f0f0f0">
        <div style="font-size:14px;font-weight:500;margin:0 0 4px 0;display:flex;align-items:center;gap:8px">
          <span style="width:10px;height:10px;border-radius:50%;display:inline-block;flex-shrink:0;background-color:\${cat.color}"></span>
          \${m.title}
        </div>
        \${m.description ? '<div style="font-size:12px;color:#666;margin:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + m.description + '</div>' : ''}
        <div style="font-size:11px;color:#999;margin-top:2px">\${cat.name}</div>
      </div>\`;
    }).join('');

    // Re-bind click events
    list.querySelectorAll('.marker-item').forEach(el => {
      el.addEventListener('click', () => {
        const lat = parseFloat(el.dataset.lat);
        const lng = parseFloat(el.dataset.lng);
        map.setView([lat, lng], 16);
        const lm = leafletMarkers[el.dataset.markerId];
        if (lm) lm.openPopup();
      });
    });
  };

  // Category filter
  const refreshFilterBar = () => {
    const bar = document.getElementById('filter-bar');
    bar.innerHTML = categoriesData.map(cat => {
      const active = activeCategories.includes(cat.id);
      const style = active
        ? \`background-color:\${cat.color};color:#fff;border-color:\${cat.color}\`
        : \`background-color:#fff;color:\${cat.color};border-color:\${cat.color}\`;
      return \`<button class="filter-chip" data-category-id="\${cat.id}" style="\${style};padding:4px 10px;border-radius:12px;font-size:12px;font-weight:500;cursor:pointer;border-width:2px;border-style:solid">\${cat.name}</button>\`;
    }).join('');

    bar.querySelectorAll('.filter-chip').forEach(el => {
      el.addEventListener('click', () => {
        const id = el.dataset.categoryId;
        if (activeCategories.includes(id)) {
          activeCategories = activeCategories.filter(c => c !== id);
        } else {
          activeCategories.push(id);
        }
        renderMarkers();
        refreshSidebar();
        refreshFilterBar();
      });
    });
  };
  refreshFilterBar();

  // Search
  const searchInput = document.getElementById('search-input');
  const searchBtn = document.getElementById('search-btn');
  const searchResults = document.getElementById('search-results');

  const doSearch = async () => {
    const q = searchInput.value.trim();
    if (!q) return;
    searchBtn.textContent = '...';
    try {
      const resp = await fetch('/api/search?q=' + encodeURIComponent(q));
      const results = await resp.json();
      if (results.length === 0) {
        searchResults.innerHTML = '<div class="search-result-item" style="color:#999">No results found</div>';
      } else {
        searchResults.innerHTML = results.map(r =>
          \`<div class="search-result-item" data-lat="\${r.lat}" data-lng="\${r.lng}">\${r.displayName}</div>\`
        ).join('');
        searchResults.querySelectorAll('.search-result-item').forEach(el => {
          el.addEventListener('click', () => {
            const lat = parseFloat(el.dataset.lat);
            const lng = parseFloat(el.dataset.lng);
            if (!isNaN(lat) && !isNaN(lng)) {
              map.setView([lat, lng], 15);
              searchResults.style.display = 'none';
              searchInput.value = el.textContent;
            }
          });
        });
      }
      searchResults.style.display = 'block';
    } catch(e) {
      searchResults.innerHTML = '<div class="search-result-item" style="color:#e74c3c">Search failed</div>';
      searchResults.style.display = 'block';
    }
    searchBtn.textContent = 'Search';
  };

  searchBtn.addEventListener('click', doSearch);
  searchInput.addEventListener('keydown', (e) => { if (e.key === 'Enter') doSearch(); });
  document.addEventListener('click', (e) => {
    if (!document.getElementById('search-wrapper').contains(e.target)) {
      searchResults.style.display = 'none';
    }
  });

  // Modal helpers
  const showModal = (html) => {
    const root = document.getElementById('modal-root');
    root.innerHTML = \`<div class="modal-overlay" id="modal-overlay"><div class="modal">\${html}</div></div>\`;
    document.getElementById('modal-overlay').addEventListener('click', (e) => {
      if (e.target.id === 'modal-overlay') closeModal();
    });
  };
  const closeModal = () => { document.getElementById('modal-root').innerHTML = ''; };

  // Map click handler
  map.on('click', (e) => {
    if (addMode === 'marker') {
      addMode = null;
      map.getContainer().style.cursor = '';
      const catOptions = categoriesData.map(c => \`<option value="\${c.id}">\${c.name}</option>\`).join('');
      showModal(\`
        <h3>Add Marker</h3>
        <label>Title</label>
        <input id="m-title" type="text" placeholder="Marker title" />
        <label>Description</label>
        <textarea id="m-desc" placeholder="Optional description"></textarea>
        <label>Category</label>
        <select id="m-cat">\${catOptions}</select>
        <div style="font-size:12px;color:#888;margin-bottom:8px">Location: \${e.latlng.lat.toFixed(5)}, \${e.latlng.lng.toFixed(5)}</div>
        <div class="modal-actions">
          <button id="m-cancel">Cancel</button>
          <button id="m-save" class="btn-primary">Save</button>
        </div>
      \`);
      document.getElementById('m-cancel').addEventListener('click', closeModal);
      document.getElementById('m-save').addEventListener('click', async () => {
        const title = document.getElementById('m-title').value.trim();
        if (!title) { document.getElementById('m-title').style.borderColor = '#e74c3c'; return; }
        const body = {
          lat: e.latlng.lat, lng: e.latlng.lng,
          title, description: document.getElementById('m-desc').value.trim(),
          categoryId: document.getElementById('m-cat').value,
        };
        const resp = await fetch('/api/markers', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
        const newMarker = await resp.json();
        markersData.push(newMarker);
        renderMarkers();
        refreshSidebar();
        closeModal();
      });
    } else if (addMode === 'circle') {
      addMode = null;
      map.getContainer().style.cursor = '';
      showModal(\`
        <h3>Add Circle</h3>
        <label>Label</label>
        <input id="c-label" type="text" placeholder="Circle label" />
        <label>Radius (meters)</label>
        <input id="c-radius" type="number" value="500" min="10" />
        <label>Color</label>
        <input id="c-color" type="color" value="#3388ff" />
        <div style="font-size:12px;color:#888;margin-bottom:8px">Center: \${e.latlng.lat.toFixed(5)}, \${e.latlng.lng.toFixed(5)}</div>
        <div class="modal-actions">
          <button id="c-cancel">Cancel</button>
          <button id="c-save" class="btn-primary">Save</button>
        </div>
      \`);
      document.getElementById('c-cancel').addEventListener('click', closeModal);
      document.getElementById('c-save').addEventListener('click', async () => {
        const body = {
          lat: e.latlng.lat, lng: e.latlng.lng,
          radius: parseFloat(document.getElementById('c-radius').value) || 500,
          color: document.getElementById('c-color').value,
          label: document.getElementById('c-label').value.trim(),
        };
        const resp = await fetch('/api/circles', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify(body) });
        const newCircle = await resp.json();
        circlesData.push(newCircle);
        renderCircles();
        closeModal();
      });
    }
  });

  // Button handlers
  document.getElementById('btn-add-marker').addEventListener('click', () => {
    addMode = 'marker';
    map.getContainer().style.cursor = 'crosshair';
  });

  document.getElementById('btn-add-circle').addEventListener('click', () => {
    addMode = 'circle';
    map.getContainer().style.cursor = 'crosshair';
  });

  // Categories manager
  document.getElementById('btn-manage-cats').addEventListener('click', () => {
    const rows = categoriesData.map(c =>
      \`<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid #f0f0f0">
        <span style="width:16px;height:16px;border-radius:50%;background:\${c.color};flex-shrink:0"></span>
        <span style="flex:1;font-size:14px">\${c.name}</span>
        \${c.id !== 'default' ? '<button class="cat-delete" data-cat-id="' + c.id + '" style="padding:2px 8px;font-size:12px;border:1px solid #e74c3c;color:#e74c3c;background:#fff;border-radius:4px;cursor:pointer">Delete</button>' : ''}
      </div>\`
    ).join('');

    showModal(\`
      <h3>Categories</h3>
      <div style="margin-bottom:12px">\${rows}</div>
      <div style="border-top:1px solid #e0e0e0;padding-top:12px">
        <label>New Category</label>
        <div style="display:flex;gap:8px">
          <input id="new-cat-name" type="text" placeholder="Category name" style="flex:1" />
          <input id="new-cat-color" type="color" value="#3388ff" style="width:50px;padding:4px" />
          <button id="new-cat-add" class="btn-primary" style="padding:8px 14px;border-radius:6px;font-size:14px;cursor:pointer;border:none">Add</button>
        </div>
      </div>
      <div class="modal-actions"><button id="cat-close">Close</button></div>
    \`);

    document.getElementById('cat-close').addEventListener('click', closeModal);
    document.getElementById('new-cat-add').addEventListener('click', async () => {
      const name = document.getElementById('new-cat-name').value.trim();
      if (!name) return;
      const color = document.getElementById('new-cat-color').value;
      const resp = await fetch('/api/categories', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ name, color }) });
      const cat = await resp.json();
      categoriesData.push(cat);
      activeCategories.push(cat.id);
      refreshFilterBar();
      closeModal();
      document.getElementById('btn-manage-cats').click();
    });

    document.querySelectorAll('.cat-delete').forEach(el => {
      el.addEventListener('click', async () => {
        const id = el.dataset.catId;
        await fetch('/api/categories/' + id, { method: 'DELETE' });
        const idx = categoriesData.findIndex(c => c.id === id);
        if (idx > -1) categoriesData.splice(idx, 1);
        activeCategories = activeCategories.filter(c => c !== id);
        markersData.forEach(m => { if (m.categoryId === id) m.categoryId = 'default'; });
        renderMarkers();
        refreshSidebar();
        refreshFilterBar();
        closeModal();
        document.getElementById('btn-manage-cats').click();
      });
    });
  });

  // Delete handlers
  window.__deleteMarker = async (id) => {
    await fetch('/api/markers/' + id, { method: 'DELETE' });
    const idx = markersData.findIndex(m => m.id === id);
    if (idx > -1) markersData.splice(idx, 1);
    renderMarkers();
    refreshSidebar();
  };

  window.__deleteCircle = async (id) => {
    await fetch('/api/circles/' + id, { method: 'DELETE' });
    const idx = circlesData.findIndex(c => c.id === id);
    if (idx > -1) circlesData.splice(idx, 1);
    renderCircles();
  };

  // Save state on move
  map.on('moveend', () => {
    const c = map.getCenter();
    fetch('/api/state', {
      method: 'POST',
      headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ center: { lat: c.lat, lng: c.lng }, zoom: map.getZoom() }),
    });
  });
})();
        `
      )
    )
  )

  const ssr = createSSR()
  return '<!DOCTYPE html>' + ssr(template)
}

import {
  getMarkers,
  getCircles,
  getCategories,
  getState,
  addMarker,
  removeMarker,
  updateMarker,
  addCircle,
  removeCircle,
  addCategory,
  removeCategory,
  saveState,
} from './store'
import { searchLocation } from './search'
import { renderMap } from './render'

const PORT = parseInt(process.env.PORT ?? '3000', 10)

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string): Response =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => req.json() as Promise<T>

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // Serve the main page
    if (pathname === '/' && method === 'GET') {
      const [markers, circles, categories, state] = await Promise.all([
        getMarkers(),
        getCircles(),
        getCategories(),
        getState(),
      ])
      const html = renderMap({ markers, circles, categories, state })
      return htmlResponse(html)
    }

    // Search API
    if (pathname === '/api/search' && method === 'GET') {
      const query = url.searchParams.get('q') ?? ''
      if (!query) return jsonResponse([])
      const results = await searchLocation(query)
      return jsonResponse(results)
    }

    // Markers CRUD
    if (pathname === '/api/markers' && method === 'GET') {
      return jsonResponse(await getMarkers())
    }

    if (pathname === '/api/markers' && method === 'POST') {
      const body = await parseBody<{
        lat: number
        lng: number
        title: string
        description: string
        categoryId: string
      }>(req)
      const marker = await addMarker(body)
      return jsonResponse(marker, 201)
    }

    if (pathname.startsWith('/api/markers/') && method === 'DELETE') {
      const id = pathname.slice('/api/markers/'.length)
      const removed = await removeMarker(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    if (pathname.startsWith('/api/markers/') && method === 'PATCH') {
      const id = pathname.slice('/api/markers/'.length)
      const updates = await parseBody<Partial<{ title: string; description: string; categoryId: string }>>(req)
      const updated = await updateMarker(id, updates)
      return updated ? jsonResponse(updated) : jsonResponse({ error: 'Not found' }, 404)
    }

    // Circles CRUD
    if (pathname === '/api/circles' && method === 'GET') {
      return jsonResponse(await getCircles())
    }

    if (pathname === '/api/circles' && method === 'POST') {
      const body = await parseBody<{
        lat: number
        lng: number
        radius: number
        color: string
        label: string
      }>(req)
      const circle = await addCircle(body)
      return jsonResponse(circle, 201)
    }

    if (pathname.startsWith('/api/circles/') && method === 'DELETE') {
      const id = pathname.slice('/api/circles/'.length)
      const removed = await removeCircle(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    // Categories CRUD
    if (pathname === '/api/categories' && method === 'GET') {
      return jsonResponse(await getCategories())
    }

    if (pathname === '/api/categories' && method === 'POST') {
      const body = await parseBody<{ name: string; color: string }>(req)
      const category = await addCategory(body)
      return jsonResponse(category, 201)
    }

    if (pathname.startsWith('/api/categories/') && method === 'DELETE') {
      const id = pathname.slice('/api/categories/'.length)
      const removed = await removeCategory(id)
      return removed ? jsonResponse({ ok: true }) : jsonResponse({ error: 'Not found' }, 404)
    }

    // Map state
    if (pathname === '/api/state' && method === 'POST') {
      const state = await parseBody<{ center: { lat: number; lng: number }; zoom: number }>(req)
      await saveState(state)
      return jsonResponse({ ok: true })
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

console.log(`Interactive Map running at http://localhost:${server.port}`)
